interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];

const sumItemBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumOf(item), 0);

const quoteStep = (step: QuoteStep): { premium: number } => {
  const itemsBase = sumItemBasePremiums(step.items);
  const firstInsuranceSurcharge = itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
  return { premium: itemsBase + firstInsuranceSurcharge + PROCESSING_FEE };
};

export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map(quoteStep);
  return { results };
};

